import{_ as n,o as a,c as o,a2 as l}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse(`{"title":"Strings in Rust","description":"Navigating Rust's string types — String vs &str — and understanding UTF-8 encoding compared to Python's str.","frontmatter":{"title":"Strings in Rust","description":"Navigating Rust's string types — String vs &str — and understanding UTF-8 encoding compared to Python's str."},"headers":[],"relativePath":"learn/linear/02-rust-for-python-developers/13-strings-in-rust.md","filePath":"learn/linear/02-rust-for-python-developers/13-strings-in-rust.md"}`),t={name:"learn/linear/02-rust-for-python-developers/13-strings-in-rust.md"};function p(e,s,c,r,y,i){return a(),o("div",null,[...s[0]||(s[0]=[l(`<h1 id="strings-in-rust" tabindex="-1">Strings in Rust <a class="header-anchor" href="#strings-in-rust" aria-label="Permalink to &quot;Strings in Rust&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>Why Rust has two main string types (String and &amp;str) and when to use each</li><li>How Rust enforces valid UTF-8 encoding and what that means for string manipulation</li><li>Common string operations like formatting, slicing, and concatenation compared to Python equivalents</li></ul></blockquote><p>Strings in Rust confuse every Python developer at first. In Python, there is one string type: <code>str</code>. It holds Unicode text, you can slice it, concatenate it, and never think about encoding. In Rust, there are two main string types, and understanding why they exist is essential.</p><h2 id="the-two-string-types" tabindex="-1">The two string types <a class="header-anchor" href="#the-two-string-types" aria-label="Permalink to &quot;The two string types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Owned?</th><th>Growable?</th><th>Where it lives</th><th>Python equivalent</th></tr></thead><tbody><tr><td><code>String</code></td><td>Yes</td><td>Yes</td><td>Heap</td><td><code>str</code> (most similar)</td></tr><tr><td><code>&amp;str</code></td><td>No (borrowed)</td><td>No</td><td>Anywhere</td><td>A read-only view of a <code>str</code></td></tr></tbody></table><p><strong><code>String</code></strong> is an owned, heap-allocated, growable string. You use it when you need to create, modify, or own string data.</p><p><strong><code>&amp;str</code></strong> (pronounced &quot;string slice&quot;) is a <em>reference</em> to string data. It is a view into a <code>String</code>, a string literal, or any contiguous UTF-8 bytes. You use it when you just need to read string data.</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // String — owned, on the heap, can be modified</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CBA6F7;"> mut</span><span style="color:#CDD6F4;"> owned </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Hello&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#CDD6F4;">    owned</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push_str</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;, world!&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> owned</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">  // &quot;Hello, world!&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // &amp;str — a borrowed view, read-only</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> slice</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#94E2D5;"> =</span><span style="color:#A6E3A1;"> &quot;Hello, world!&quot;</span><span style="color:#9399B2;">;</span><span style="color:#6C7086;font-style:italic;">  // string literals are &amp;str</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> slice</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // A &amp;str can borrow from a String</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> view</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#94E2D5;"> =</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CDD6F4;">owned</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> view</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>Think of it this way:</p><ul><li><code>String</code> is like Python&#39;s <code>str</code> — you can create it, modify it, pass it around, and it manages its own memory</li><li><code>&amp;str</code> is like a <code>memoryview</code> or a read-only slice of a string — it points to data owned by someone else</li></ul><p>In Python, you never make this distinction because Python handles memory automatically. In Rust, the distinction matters because it tells the compiler who is responsible for the memory and what operations are safe.</p><p>The good news: once you internalize that function parameters should usually take <code>&amp;str</code> and function return values should usually return <code>String</code>, most string decisions become automatic.</p></div><h2 id="creating-strings" tabindex="-1">Creating strings <a class="header-anchor" href="#creating-strings" aria-label="Permalink to &quot;Creating strings&quot;">​</a></h2><p>There are several ways to create <code>String</code> values:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // From a string literal</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> s1 </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;hello&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> s2 </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;hello&quot;</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">to_string</span><span style="color:#9399B2;">();</span><span style="color:#6C7086;font-style:italic;">  // equivalent</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // From formatting</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> name </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;Agent&quot;</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> s3 </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;font-style:italic;"> format!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Hello, </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">!&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> name</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Empty string, then build it up</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CBA6F7;"> mut</span><span style="color:#CDD6F4;"> s4 </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#CDD6F4;">    s4</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push_str</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Hello&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#CDD6F4;">    s4</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push</span><span style="color:#9399B2;">(</span><span style="color:#9399B2;">&#39;</span><span style="color:#9399B2;"> &#39;</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">  // push a single char</span></span>
<span class="line"><span style="color:#CDD6F4;">    s4</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push_str</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;world&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // From other types</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> s5 </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 42</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">to_string</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> s6 </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;"> true</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">to_string</span><span style="color:#9399B2;">();</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> | </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> | </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> | </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> | </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> | </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> s1</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> s2</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> s3</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> s4</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> s5</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> s6</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>In Python, you create strings with literals, f-strings, <code>str()</code>, and <code>.join()</code>. The Rust equivalents:</p><table tabindex="0"><thead><tr><th>Python</th><th>Rust</th></tr></thead><tbody><tr><td><code>&quot;hello&quot;</code></td><td><code>&quot;hello&quot;</code> (this is <code>&amp;str</code>) or <code>String::from(&quot;hello&quot;)</code></td></tr><tr><td><code>f&quot;Hello, {name}!&quot;</code></td><td><code>format!(&quot;Hello, {}!&quot;, name)</code></td></tr><tr><td><code>str(42)</code></td><td><code>42.to_string()</code></td></tr><tr><td><code>&quot;&quot;.join(parts)</code></td><td><code>parts.join(&quot;&quot;)</code> or <code>parts.concat()</code></td></tr><tr><td><code>s = &quot;&quot;; s += &quot;hello&quot;</code></td><td><code>let mut s = String::new(); s.push_str(&quot;hello&quot;);</code></td></tr></tbody></table></div><h2 id="concatenation" tabindex="-1">Concatenation <a class="header-anchor" href="#concatenation" aria-label="Permalink to &quot;Concatenation&quot;">​</a></h2><p>String concatenation in Rust looks different from Python:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Using format! (most common and readable)</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> first </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;Hello&quot;</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> second </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;world&quot;</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> combined </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;font-style:italic;"> format!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">, </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">!&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> first</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> second</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> combined</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Using push_str (mutating an existing String)</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CBA6F7;"> mut</span><span style="color:#CDD6F4;"> greeting </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Hello&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#CDD6F4;">    greeting</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push_str</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;, &quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#CDD6F4;">    greeting</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push_str</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;world!&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> greeting</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Using + operator (takes ownership of left side)</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> hello </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Hello&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> world </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;, world!&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> combined </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> hello </span><span style="color:#94E2D5;">+</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CDD6F4;">world</span><span style="color:#9399B2;">;</span><span style="color:#6C7086;font-style:italic;">  // hello is moved, world is borrowed</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // println!(&quot;{}&quot;, hello);</span><span style="color:#6C7086;font-style:italic;">  // ERROR: hello was moved</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> combined</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Joining a collection (like Python&#39;s &quot;sep&quot;.join(list))</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> parts </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;font-style:italic;"> vec!</span><span style="color:#9399B2;">[</span><span style="color:#A6E3A1;">&quot;one&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;two&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;three&quot;</span><span style="color:#9399B2;">];</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> joined </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> parts</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">join</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;, &quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> joined</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">  // &quot;one, two, three&quot;</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>Python&#39;s <code>+</code> creates a new string from two existing strings, and both originals remain valid. Rust&#39;s <code>+</code> is different — it takes ownership of the left operand and borrows the right. This is efficient (it can reuse the left string&#39;s buffer) but surprising.</p><p>For readability, prefer <code>format!()</code> — it is the Rust equivalent of f-strings and the most idiomatic way to combine strings:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Python</span></span>
<span class="line"><span style="color:#CDD6F4;">result </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;font-style:italic;"> f</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#F5C2E7;">{</span><span style="color:#CDD6F4;">first</span><span style="color:#F5C2E7;">}</span><span style="color:#A6E3A1;">, </span><span style="color:#F5C2E7;">{</span><span style="color:#CDD6F4;">second</span><span style="color:#F5C2E7;">}</span><span style="color:#A6E3A1;">!&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Rust</span></span>
<span class="line"><span style="color:#CDD6F4;">let result </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;font-style:italic;"> format</span><span style="color:#CDD6F4;">!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#F5C2E7;">{}</span><span style="color:#A6E3A1;">, </span><span style="color:#F5C2E7;">{}</span><span style="color:#A6E3A1;">!&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> first</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> second</span><span style="color:#9399B2;">)</span><span style="color:#CDD6F4;">;</span></span></code></pre></div></div><h2 id="string-slicing-and-indexing" tabindex="-1">String slicing and indexing <a class="header-anchor" href="#string-slicing-and-indexing" aria-label="Permalink to &quot;String slicing and indexing&quot;">​</a></h2><p>Here is a critical difference: you <strong>cannot index a Rust string by position</strong>.</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> hello </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Hello&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // This does NOT work:</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // let h = hello[0];</span><span style="color:#6C7086;font-style:italic;">  // ERROR: String cannot be indexed by integer</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Use .chars() to iterate over characters</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> first_char </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> hello</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">chars</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">next</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">:?</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> first_char</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">  // Some(&#39;H&#39;)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Use byte slicing (careful — must be at character boundaries)</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> slice </span><span style="color:#94E2D5;">=</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CDD6F4;">hello</span><span style="color:#9399B2;">[</span><span style="color:#FAB387;">0</span><span style="color:#94E2D5;">..</span><span style="color:#FAB387;">5</span><span style="color:#9399B2;">];</span><span style="color:#6C7086;font-style:italic;">  // &quot;Hello&quot; — works because all chars are 1 byte</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> slice</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Iterating over characters</span></span>
<span class="line"><span style="color:#CBA6F7;">    for</span><span style="color:#CDD6F4;"> c </span><span style="color:#CBA6F7;">in</span><span style="color:#CDD6F4;"> hello</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">chars</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">        print!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> c</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">();</span><span style="color:#6C7086;font-style:italic;">  // H e l l o</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Getting the nth character</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> third </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> hello</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">chars</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">nth</span><span style="color:#9399B2;">(</span><span style="color:#FAB387;">2</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">:?</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> third</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">  // Some(&#39;l&#39;)</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Why no indexing? Because Rust strings are UTF-8, and characters can be 1 to 4 bytes. The string <code>&quot;cafe&quot;</code> has different byte offsets than <code>&quot;caf\\u{00e9}&quot;</code> even though they look similar. Indexing by byte position could land in the middle of a multi-byte character.</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>In Python, <code>&quot;hello&quot;[0]</code> gives you <code>&quot;h&quot;</code> and it seems simple. But Python strings are stored as Unicode code points, so indexing is O(1). Rust strings are stored as UTF-8 bytes, so finding the nth character requires scanning from the beginning — it would be O(n). Rust refuses to hide this cost behind an innocent-looking <code>[0]</code> syntax.</p><p>If you need O(1) indexing, convert to a <code>Vec&lt;char&gt;</code> first:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">let</span><span style="color:#CDD6F4;"> chars</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Vec</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">char</span><span style="color:#89DCEB;">&gt;</span><span style="color:#94E2D5;"> =</span><span style="color:#A6E3A1;"> &quot;hello&quot;</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">chars</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">collect</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#CBA6F7;">let</span><span style="color:#CDD6F4;"> first </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> chars</span><span style="color:#9399B2;">[</span><span style="color:#FAB387;">0</span><span style="color:#9399B2;">];</span><span style="color:#6C7086;font-style:italic;">  // &#39;h&#39; — O(1) access</span></span></code></pre></div><p>This is like Python&#39;s <code>list(&quot;hello&quot;)</code>.</p></div><h2 id="common-string-methods" tabindex="-1">Common string methods <a class="header-anchor" href="#common-string-methods" aria-label="Permalink to &quot;Common string methods&quot;">​</a></h2><p>Here is a reference of Python string methods and their Rust equivalents:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> text </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;  Hello, World!  &quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Trimming (Python: strip/lstrip/rstrip)</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> trimmed </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> text</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">trim</span><span style="color:#9399B2;">();</span><span style="color:#6C7086;font-style:italic;">                        // &quot;Hello, World!&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> left_trimmed </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> text</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">trim_start</span><span style="color:#9399B2;">();</span><span style="color:#6C7086;font-style:italic;">              // &quot;Hello, World!  &quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> right_trimmed </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> text</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">trim_end</span><span style="color:#9399B2;">();</span><span style="color:#6C7086;font-style:italic;">               // &quot;  Hello, World!&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Case conversion</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> upper </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;hello&quot;</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">to_uppercase</span><span style="color:#9399B2;">();</span><span style="color:#6C7086;font-style:italic;">                // &quot;HELLO&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> lower </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;HELLO&quot;</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">to_lowercase</span><span style="color:#9399B2;">();</span><span style="color:#6C7086;font-style:italic;">                // &quot;hello&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Checking content</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> starts </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;Hello&quot;</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">starts_with</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;He&quot;</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">            // true</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> ends </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;Hello&quot;</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">ends_with</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;lo&quot;</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">                // true</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> has </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;Hello World&quot;</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">contains</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;World&quot;</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">         // true</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> empty </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;&quot;</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">is_empty</span><span style="color:#9399B2;">();</span><span style="color:#6C7086;font-style:italic;">                         // true</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Splitting (Python: split)</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> parts</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Vec</span><span style="color:#89DCEB;">&lt;</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#89DCEB;">&gt;</span><span style="color:#94E2D5;"> =</span><span style="color:#A6E3A1;"> &quot;a,b,c&quot;</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">split</span><span style="color:#9399B2;">(</span><span style="color:#9399B2;">&#39;</span><span style="color:#A6E3A1;">,</span><span style="color:#9399B2;">&#39;</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">collect</span><span style="color:#9399B2;">();</span><span style="color:#6C7086;font-style:italic;">  // [&quot;a&quot;, &quot;b&quot;, &quot;c&quot;]</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> words</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Vec</span><span style="color:#89DCEB;">&lt;</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#89DCEB;">&gt;</span><span style="color:#94E2D5;"> =</span><span style="color:#A6E3A1;"> &quot;hello world&quot;</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">split_whitespace</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">collect</span><span style="color:#9399B2;">();</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Replacing (Python: replace)</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> replaced </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;hello world&quot;</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">replace</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;world&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;Rust&quot;</span><span style="color:#9399B2;">);</span><span style="color:#6C7086;font-style:italic;">  // &quot;hello Rust&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Length</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> byte_len </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;hello&quot;</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">len</span><span style="color:#9399B2;">();</span><span style="color:#6C7086;font-style:italic;">          // 5 (byte length!)</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> char_count </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;hello&quot;</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">chars</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">count</span><span style="color:#9399B2;">();</span><span style="color:#6C7086;font-style:italic;">  // 5 (character count)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> | </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> | </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> | </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> | </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> | </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> | </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> | </span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">:?</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;"> | </span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">:?</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;"> | </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> | </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> | </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">        trimmed</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> left_trimmed</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> right_trimmed</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> upper</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> lower</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">        starts</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> ends</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> parts</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> words</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> replaced</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> byte_len</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> char_count</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#9399B2;"> {}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> has</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> empty</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>Most operations have direct equivalents:</p><table tabindex="0"><thead><tr><th>Python</th><th>Rust</th><th>Note</th></tr></thead><tbody><tr><td><code>s.strip()</code></td><td><code>s.trim()</code></td><td>Returns <code>&amp;str</code></td></tr><tr><td><code>s.upper()</code></td><td><code>s.to_uppercase()</code></td><td>Returns new <code>String</code></td></tr><tr><td><code>s.startswith(&quot;x&quot;)</code></td><td><code>s.starts_with(&quot;x&quot;)</code></td><td>Returns <code>bool</code></td></tr><tr><td><code>s.split(&quot;,&quot;)</code></td><td><code>s.split(&#39;,&#39;).collect::&lt;Vec&lt;_&gt;&gt;()</code></td><td>Lazy iterator, must collect</td></tr><tr><td><code>s.replace(&quot;a&quot;, &quot;b&quot;)</code></td><td><code>s.replace(&quot;a&quot;, &quot;b&quot;)</code></td><td>Same name!</td></tr><tr><td><code>len(s)</code></td><td><code>s.len()</code></td><td><strong>Bytes</strong>, not chars</td></tr><tr><td><code>len(s)</code> (char count)</td><td><code>s.chars().count()</code></td><td>Character count</td></tr></tbody></table><p>The biggest gotcha: <code>.len()</code> in Rust returns byte length, not character count. For ASCII strings they are the same, but for emoji or accented characters they differ.</p></div><h2 id="when-to-use-string-vs-str" tabindex="-1">When to use <code>String</code> vs <code>&amp;str</code> <a class="header-anchor" href="#when-to-use-string-vs-str" aria-label="Permalink to &quot;When to use \`String\` vs \`&amp;str\`&quot;">​</a></h2><p>Here is a practical guide:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Function parameters: prefer &amp;str — accepts both String and &amp;str</span></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> greet</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;">name</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    format!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Hello, </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">!&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> name</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// Struct fields that own data: use String</span></span>
<span class="line"><span style="color:#CBA6F7;">struct</span><span style="color:#F9E2AF;font-style:italic;"> Message</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    role</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    content</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// Returning new string data: return String</span></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> build_prompt</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;">messages</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">Message</span><span style="color:#9399B2;">])</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CBA6F7;"> mut</span><span style="color:#CDD6F4;"> prompt </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#CBA6F7;">    for</span><span style="color:#CDD6F4;"> msg </span><span style="color:#CBA6F7;">in</span><span style="color:#CDD6F4;"> messages </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CDD6F4;">        prompt</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push_str</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#89B4FA;font-style:italic;">format!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;[</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">]: </span><span style="color:#9399B2;">{}</span><span style="color:#F5C2E7;">\\n</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> msg</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">role</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> msg</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">content</span><span style="color:#9399B2;">));</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#CDD6F4;">    prompt</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Works with &amp;str (string literal)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#89B4FA;font-style:italic;"> greet</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;World&quot;</span><span style="color:#9399B2;">));</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Works with &amp;String (reference to owned String)</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> name </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Agent&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#89B4FA;font-style:italic;"> greet</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">name</span><span style="color:#9399B2;">));</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The rule of thumb:</p><ul><li><strong>Function parameters</strong>: <code>&amp;str</code> (accepts both <code>String</code> and string literals)</li><li><strong>Struct fields</strong>: <code>String</code> (the struct needs to own the data)</li><li><strong>Return values</strong>: <code>String</code> (the caller needs owned data)</li><li><strong>Constants</strong>: <code>&amp;str</code> or <code>&amp;&#39;static str</code> (compile-time string data)</li></ul><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Rust has two main string types: <code>String</code> (owned, growable, heap-allocated) and <code>&amp;str</code> (borrowed, read-only view) — use <code>&amp;str</code> for function parameters and <code>String</code> for owned data</li><li>You cannot index strings by position because Rust strings are UTF-8 and characters can be multiple bytes — use <code>.chars()</code> to iterate over characters</li><li><code>.len()</code> returns byte length, not character count — use <code>.chars().count()</code> for character count</li><li><code>format!()</code> is the idiomatic way to build strings in Rust, equivalent to Python&#39;s f-strings</li><li>Most Python string methods have direct Rust equivalents: <code>trim</code>, <code>to_uppercase</code>, <code>starts_with</code>, <code>split</code>, <code>replace</code>, and <code>contains</code> all work similarly</li></ul>`,33)])])}const B=n(t,[["render",p]]);export{u as __pageData,B as default};
